			Уведомления в телеграм
		</button>
	</section>

	<section id="main" class="box">
		{@render children()}
	</section>
</main>

<style lang="scss">
	@use "$scss/mixins/scr";

	.container {
		display: grid;
		grid-template-columns: 1fr 2fr;
		gap: 20px;
		margin-top: 50px;

		@include scr.tablet {
			grid-template-columns: 1fr;
		}
	}

	#account-credentials {
		display: flex;
		align-items: center;
		gap: 20px;
	}

	.to_settings {
    display: flex;
    margin-left: auto;
		padding: 5px;
		background: none;
		border-radius: 10em;
    border: 1px solid #E5E7EB;
	}

	.thumb {
		position: relative;
		display: flex;

		width: 100px;
		height: 100px;

		svg {
			position: absolute;
			top: 0;
			left: 0;
			bottom: 0;
			right: 0;
		}

		img {
			display: block;
			margin: auto;
			width: 72px;
			height: 72px;
			border-radius: 10em;
		}
	}

	.info {
		span {
			display: block;
		}

		span:last-child {
			margin-top: 5px;
			font-size: 0.75em;
			color: var(--text-content-color);
		}
	}

	#subscription {
		display: flex;
		gap: 20px;
		align-items: center;
		justify-content: space-between;

		.status {
			.badge {
				font-size: 0.75em;
				width: fit-content;
				padding: 2px 10px;
				background: #f2f2f2;
				margin-top: 10px;
			}

      @include scr.tablet {
        h1 {
          font-size: 1rem;
        }
        .badge {
					font-size: .75rem;
				}
      }
		}

		.type {
			text-align: right;

			div:first-child {
				background: linear-gradient(90deg, #f66d49 0%, #f43f5e 100%);
				-webkit-background-clip: text;
				background-clip: text;

				color: transparent;
				font-size: 1.85rem;
				font-weight: 600;

        @include scr.tablet {
					font-size: 1.25rem;
        }
			}

			div:last-child {
				font-size: .85em;
				color: var(--text-content-color);

        @include scr.tablet {
          font-size: .75rem;
        }
			}
		}

		.go-to {
			display: flex;
			align-items: center;
			gap: 20px;

      margin-left: auto;

			.to-subscription {
				width: 56px;
				height: 56px;
				border-radius: 10em;
				padding: 0;

				@include scr.mobile {
					width: 30px;
					height: 30px;

					:global svg {
						width: 15px;
						height: 15px;
					}
				}
			}
		}

		.activate {
			font-size: 1.15em;
			font-weight: 600;
		}
	}

	#nav {
		.nav {
			a {
				display: flex;
				justify-content: space-between;
				align-items: center;
				border-radius: 10px;
				height: 56px;
				padding: 20px;
			}

			a.active {
				background: #f2f2f2;
			}

			a + a {
				margin-top: 5px;
			}
		}
	}

	#tg-notifications {
		width: 100%;
		margin-top: 20px;
	}

	#main {
		display: flex;
		flex-direction: column;
		gap: 20px;
		color: var(--text-content-color);
	}
</style>
